mapper.update:
        UPDATE esg.tb_risk_and_ops_asmt_criteria_detail
	       SET content1 = #{content1},
	           content2 = #{content2},
		       content3 = #{content3},
		       content4 = #{content4},
	           ord_seq = #{ordSeq}::integer,
	           use_yn = #{detailUseYn},
	           updated_at = now(),
	           updated_by = #{updatedBy}
	     WHERE criteria_id = #{criteriaId}
		   AND detail_type = #{detailType}
		   AND detail_seq = #{detailSeq}

        UPDATE esg.tb_risk_and_ops_asmt_criteria
	       SET use_yn = #{useYn},
      		   updated_at = now(),
	           updated_by = #{updatedBy}
	     WHERE criteria_id = #{criteriaId}

mapper.delete:
        UPDATE esg.tb_risk_and_ops_asmt_criteria
       	   SET use_yn = 'N',
       	   	   updated_at = now(),
	           updated_by = #{updatedBy}
         WHERE criteria_id = #{criteriaId}

        UPDATE esg.tb_risk_and_ops_asmt_criteria_detail
       	   SET use_yn = 'N',
       	   	   updated_at = now(),
	           updated_by = #{updatedBy}
         WHERE criteria_id = #{criteriaId}
           AND detail_type = #{detailType}
		   AND detail_seq = #{detailSeq}
